+
+/// Get all fixture files in a category.
+pub fn fixtures_in_category(category: &str) -> Vec<PathBuf> {
+    let dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
+        .join("tests/fixtures/html_export")
+        .join(category);
+
+    if !dir.exists() {
+        return Vec::new();
+    }
+
+    std::fs::read_dir(&dir)
+        .unwrap()
+        .filter_map(|entry| entry.ok())
+        .filter(|entry| {
+            entry
