lazy_static! {
    static ref FD_USAGE: Gauge = register_gauge!(
        "process_open_fds",
        "Number of open file descriptors"
    ).unwrap();

    static ref FD_LIMIT: Gauge = register_gauge!(
        "process_max_fds",
        "Maximum file descriptors"
    ).unwrap();
}

fn update_fd_metrics() {
    // Count FDs in /proc/self/fd
    if let Ok(entries) = std::fs::read_dir("/proc/self/fd") {
        FD_USAGE.set(entries.count() as f64);
    }

    // Get limit
    if let Ok((soft, _)) = rlimit::getrlimit(Resource::NOFILE) {
        FD_LIMIT.set(soft as f64);
    }
}
